function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

const inputItem = $json || {};
const question = clean(inputItem.input || inputItem.question || inputItem.message || inputItem.text || inputItem.chatInput || inputItem.prompt || "current weather at the farm");
const q = question.toLowerCase();

const asksForecast = /\b(forecast|tomorrow|morrow|weekend|next\s+(day|few|week)|next\s*3|coming|later|will it rain|gaan dit reen|reen later|rain expected|weather ahead|vooruitsig|vooruitsigte)\b/i.test(q);
const asksToday = /\b(today|vandag|daily|day summary|summary today|rain today|rained today|weather today|wind today|temperature today|how much rain|rain total|reen vandag|hoeveel reen)\b/i.test(q) || /\bwhat happened\b.*\btoday\b/i.test(q) || /\btoday\b.*\bwhat happened\b/i.test(q);
const asksCurrent = /\b(now|current|right now|nou|huidig|temperature now|wind now|raining now|is it raining|weather now|weather like now)\b/i.test(q);

let queryType = "current";
if (asksForecast && !asksCurrent && !asksToday) {
  queryType = "forecast";
} else if (asksToday && !asksCurrent) {
  queryType = "today";
}

const requestUrl = queryType === "forecast"
  ? "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/weather/forecast?days=3"
  : queryType === "today"
    ? "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/weather/today"
    : "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/weather/current";

return [{
  json: {
    input: question,
    query_type: queryType,
    request_url: requestUrl,
  }
}];

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function num(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function fmt(value, suffix = "") {
  const n = num(value);
  if (n === null) return "unknown";
  return `${Number.isInteger(n) ? n : Number(n.toFixed(1))}${suffix}`;
}

function formatDateTime(iso) {
  if (!iso) return "unknown";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(d);
}

function formatDate(value) {
  if (!value) return "unknown date";
  const d = new Date(`${value}T12:00:00+02:00`);
  if (Number.isNaN(d.getTime())) return value;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    weekday: "short",
    month: "short",
    day: "2-digit",
  }).format(d);
}

function sentence(value) {
  return clean(value).replace(/\s+/g, " ");
}

const route = $("Code - Route Weather Question").first()?.json || {};
const question = clean(route.input || "current weather at the farm");
const queryType = clean(route.query_type || "current");
const data = $json || {};
const success = data.success === true && data.status === "ok";
let answer = "";

if (!success) {
  const reason = sentence(data.message || data.error || data.summary?.headline || "The weather data is not available yet.");
  answer = `I could not read the weather data. ${reason}`;
} else if (queryType === "forecast") {
  const source = data.source || {};
  const summary = data.summary || {};
  const days = Array.isArray(data.days) ? data.days : [];
  const lines = [];

  lines.push("Weather forecast for Amadeus Farm:");
  lines.push("");
  if (summary.headline) lines.push(sentence(summary.headline));

  for (const day of days) {
    const flags = day.flags || {};
    const cautions = [];
    if (flags.rain_expected === true) cautions.push("rain possible");
    if (flags.strong_wind === true || flags.gust_risk === true) cautions.push("wind caution");
    if (flags.hot === true) cautions.push("hot");
    if (flags.cold === true) cautions.push("cold");

    lines.push(`- ${formatDate(day.forecast_date)}: ${fmt(day.temp_min_c, " C")} to ${fmt(day.temp_max_c, " C")}, rain ${fmt(day.rain_sum_mm, " mm")} (${fmt(day.rain_probability_max_pct, "%")}), wind max ${fmt(day.wind_max_kmh, " km/h")}, gusts ${fmt(day.gust_max_kmh, " km/h")}${cautions.length ? ` - ${cautions.join(", ")}` : ""}.`);
  }

  lines.push("");
  lines.push(`Forecast updated: ${formatDateTime(source.last_forecast_run_at)} (${source.data_age_minutes ?? "unknown"} minutes old).`);
  if (source.is_stale === true) lines.push("Warning: this forecast is stale, so treat it as the last known forecast.");

  answer = lines.join("\n");
} else if (queryType === "today") {
  const source = data.source || {};
  const window = data.window || {};
  const temperature = data.temperature || {};
  const humidity = data.humidity || {};
  const wind = data.wind || {};
  const rain = data.rain || {};
  const flags = data.flags || {};
  const summary = data.summary || {};
  const lines = [];

  lines.push("Weather today at Amadeus Farm:");
  lines.push("");
  if (summary.headline) lines.push(sentence(summary.headline));
  lines.push(`Readings: ${window.reading_count ?? "unknown"} (${window.coverage_pct ?? "unknown"}% coverage of expected 5-minute samples)`);
  lines.push(`Temperature: ${fmt(temperature.min_c, " C")} to ${fmt(temperature.max_c, " C")}, average ${fmt(temperature.avg_c, " C")}`);
  lines.push(`Humidity average: ${fmt(humidity.avg_pct, "%")}`);
  lines.push(`Rain total: ${fmt(rain.total_mm, " mm")}`);
  lines.push(`Max rain rate: ${fmt(rain.max_rate_mm_h, " mm/h")}`);
  lines.push(`Max wind: ${fmt(wind.max_speed_kmh, " km/h")}, max gust ${fmt(wind.max_gust_kmh, " km/h")}`);
  lines.push("");
  lines.push(`Window: ${formatDateTime(window.first_reading_at)} to ${formatDateTime(window.last_reading_at)}.`);

  if (flags.rain_observed === true) lines.push("Note: rain was observed today.");
  if (flags.rain_today === true && flags.rain_observed !== true) lines.push("Note: rain total is showing for today.");
  if (flags.high_wind === true || flags.gust_risk === true) lines.push("Warning: wind caution showed today.");
  if (flags.irrigation_caution === true) lines.push("Irrigation caution is showing from today's weather rules.");

  answer = lines.join("\n");
} else {
  const source = data.source || {};
  const current = data.current || {};
  const flags = data.flags || {};
  const summary = data.summary || {};
  const lines = [];

  lines.push("Current weather at Amadeus Farm:");
  lines.push("");
  if (summary.headline) lines.push(sentence(summary.headline));
  lines.push(`Temperature: ${fmt(current.temperature_c, " C")}`);
  lines.push(`Humidity: ${fmt(current.humidity_pct, "%")}`);
  lines.push(`Wind: ${fmt(current.wind_speed_kmh, " km/h")} with gusts ${fmt(current.wind_gust_kmh, " km/h")}`);
  lines.push(`Rain now: ${fmt(current.rain_rate_mm_h, " mm/h")}`);
  lines.push(`Rain today: ${fmt(current.rain_today_mm, " mm")}`);
  lines.push(`Pressure: ${fmt(current.pressure_hpa, " hPa")}`);
  lines.push("");
  lines.push(`Latest reading: ${formatDateTime(source.last_reading_at)} (${source.data_age_minutes ?? "unknown"} minutes old).`);

  if (source.is_stale === true || flags.station_stale === true) lines.push("Warning: this reading is stale, so treat it as the last known weather state.");
  if (flags.raining_now === true) lines.push("Note: it is raining now.");
  if (flags.rain_today === true && flags.raining_now !== true) lines.push("Note: rain has been recorded today.");
  if (flags.high_wind === true || flags.gust_risk === true) lines.push("Warning: wind caution is showing.");
  if (flags.irrigation_caution === true) lines.push("Irrigation caution is showing from the weather rules.");

  answer = lines.join("\n");
}

return [{
  json: {
    success,
    input: question,
    query_type: queryType,
    answer,
    output: answer,
    weather_response: answer,
    telemetry_source: queryType === "forecast" ? "backend_supabase_weather_forecast" : queryType === "today" ? "backend_supabase_weather_today" : "backend_supabase_current_weather",
    backend_payload: data,
  }
}];

